INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Live demo access$q$, $q$A public demo instance lets prospective users try the interface before self-hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Free and fully open source under the MIT license$q$, 0);
