INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$No formal SLA or enterprise support option$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$What is TRIP used for?$q$, $q$TRIP is used to pin points of interest on a map and organize them into multi-day trip itineraries, making it easier to plan and share travel routes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Is TRIP free to use?$q$, $q$Yes. TRIP is completely free and open source under the MIT license, with no paid tiers or feature gating.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Do I need to self-host TRIP?$q$, $q$Yes, TRIP has no official managed cloud version; it is deployed via Docker or Docker Compose on infrastructure you control.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Who develops TRIP?$q$, $q$TRIP is created and maintained by an independent developer known as itskovacs, distributed publicly on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Does TRIP track my data or show ads?$q$, $q$No. The project explicitly states it includes no telemetry, no tracking, and no advertisements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Can I try TRIP before self-hosting it?$q$, $q$Yes, a public demo is available at itskovacs-trip.netlify.app.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Can multiple people collaborate on a trip in TRIP?$q$, $q$Yes, trip plans can be shared with travel companions for collaborative itinerary planning.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$What technology does TRIP use?$q$, $q$TRIP is built with a TypeScript frontend and Python backend, and is distributed as a Docker container image.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Personal travel planning$q$, $q$Individuals mapping out points of interest and building day-by-day itineraries for upcoming trips.$q$, $q$Independent travelers and trip planners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Group trip coordination$q$, $q$Families or friend groups sharing a single trip plan to coordinate stops and daily schedules together.$q$, $q$Group travelers and travel companions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Self-hosted privacy-focused travel logging$q$, $q$Home-lab and self-hosting enthusiasts who want to track visited and planned places without third-party tracking.$q$, $q$Privacy-conscious self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$Self-Hosted (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited POIs and trips","Docker-based self-hosting","Full feature set with no restrictions","Community support via GitHub","Optional sponsorship via Ko-fi"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$overview$q$, $q$What Is TRIP$q$, 2, ARRAY[$q$TRIP is an open-source, self-hosted web application designed to help travelers visualize points of interest on an interactive map and organize those points into structured, multi-day trip itineraries. Built and maintained by an independent developer under the GitHub handle itskovacs, the project is distributed under the permissive MIT license, meaning anyone can run, modify, or redistribute it free of charge.$q$, $q$Unlike commercial travel-planning apps that monetize through subscriptions or advertising, TRIP is explicitly positioned around privacy and data ownership: the project states it includes no telemetry, no tracking, and no ads. Users deploy it themselves, typically via a single Docker command or Docker Compose file, and all trip and POI data lives on infrastructure the user controls.$q$, $q$The project has matured through dozens of releases and hundreds of commits, and has built a modest but engaged following in the self-hosted software community, reflected in its GitHub star count and active discussions and issue tracker.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, TRIP lets users drop pins for points of interest directly onto an interactive map, tagging and categorizing them so a growing personal database of places to visit, or places already visited, stays organized over time. These POIs can then be pulled into structured, multi-day trip itineraries that lay out where a traveler plans to be on each day of a journey.$q$, $q$Collaboration is built in: trip plans can be shared with travel companions so groups can coordinate an itinerary together rather than passing spreadsheets or screenshots back and forth. Because the whole application is self-hosted, teams or families can run a private instance accessible only to the people they invite.$q$, $q$Operationally, TRIP is designed to be lightweight and easy to deploy, shipping as a Docker image with persistent storage mounted as a volume. This keeps infrastructure requirements minimal, making it approachable for hobbyists running a home server as well as more advanced self-hosters managing a small fleet of Docker services.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TRIP has no paid tiers. It is entirely free and open source, and the full feature set is available to anyone who self-hosts it; there is no gated premium version or subscription. The only monetization path is voluntary sponsorship of the maintainer through Ko-fi, which does not unlock any additional functionality.$q$, $q$Because there is no managed cloud offering, the real cost of running TRIP is the infrastructure a user provides, such as a small VPS or home server capable of running Docker, rather than any fee paid to the project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd1da66a-312f-432a-8e37-1dc816cc5520', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Multi-target scanning$q$, $q$Scans container images, filesystems, git repositories, VM images, and Kubernetes clusters from a single tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Vulnerability detection$q$, $q$Covers both OS packages and language-specific dependencies with data from the Aqua Vulnerability Database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Misconfiguration scanning$q$, $q$Detects Infrastructure-as-Code misconfigurations across Terraform, Kubernetes manifests, and more.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Secret detection$q$, $q$Finds hardcoded credentials and exposed secrets within scanned code and images.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$SBOM generation$q$, $q$Produces a Software Bill of Materials for scanned targets to support supply-chain security.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$License scanning$q$, $q$Identifies open-source license compliance issues within dependencies.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Kubernetes Bill of Materials (KBOM)$q$, $q$Inventories Kubernetes cluster components and their associated vulnerabilities.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Zero-dependency single binary$q$, $q$Runs without a database or external middleware, simplifying CI/CD integration.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Completely free and open source under Apache 2.0 with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Single static binary with no external dependencies, simple to install and run$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Broad scanning coverage spanning five target types and four scanner engines in one tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Low false-positive rate, including on historically difficult distributions like Alpine and RHEL$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Backed by Aqua Security with active, well-funded maintenance and a large contributor base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Centralized dashboards, reporting, and runtime protection require the separate paid Aqua Platform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Can require tuning to reduce noise in very large monorepos or legacy codebases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$No built-in remediation workflow beyond CLI and CI output$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Kubernetes-native features add complexity for teams not already running container orchestration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$What is Trivy used for?$q$, $q$Trivy is used to scan containers, code repositories, filesystems, and Kubernetes clusters for vulnerabilities, misconfigurations, exposed secrets, and license issues.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Is Trivy free?$q$, $q$Yes, Trivy is completely free and open source under the Apache 2.0 license with no feature restrictions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Who maintains Trivy?$q$, $q$Trivy is maintained by Aqua Security, after being created by developer Teppei Fukuda and brought into Aqua's open-source portfolio in 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$What is the difference between Trivy and the Aqua Platform?$q$, $q$Trivy is the free open-source scanning engine, while the Aqua Platform is a separate paid commercial product built on top of Trivy that adds dashboards, runtime protection, and enterprise support.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Does Trivy scan for secrets?$q$, $q$Yes, Trivy includes a secret-scanning engine that detects hardcoded credentials and exposed secrets in code and images.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Can Trivy scan Kubernetes clusters?$q$, $q$Yes, Trivy supports scanning live Kubernetes clusters and can generate a Kubernetes Bill of Materials (KBOM).$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$What license is Trivy released under?$q$, $q$Trivy is released under the Apache 2.0 open-source license.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$How does Trivy compare to Grype or Snyk?$q$, $q$Trivy offers broader multi-target scanning (containers, IaC, secrets, licenses) in one free tool, whereas Grype focuses mainly on vulnerabilities and Snyk's core scanning is commercial with a limited free tier.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$DevSecOps CI/CD scanning$q$, $q$Embedding vulnerability and misconfiguration checks directly into build pipelines before code or images ship.$q$, $q$DevSecOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Container image security$q$, $q$Scanning container images for OS and application vulnerabilities before deployment to production.$q$, $q$Platform and container security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Cloud infrastructure-as-code audits$q$, $q$Detecting misconfigurations in Terraform and Kubernetes manifests before infrastructure is provisioned.$q$, $q$Cloud security and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Trivy Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited scans","Container image, filesystem, git repo, and Kubernetes scanning","Vulnerability, misconfiguration, secret, and license detection","SBOM generation","Apache 2.0 license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$Aqua Platform (commercial)$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Everything in Trivy open source","Centralized dashboards and reporting","Runtime protection and CNAPP capabilities","Enterprise support and SLAs","Compliance and policy management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$overview$q$, $q$What Is Trivy$q$, 2, ARRAY[$q$Trivy is a free, open-source security scanner maintained by Aqua Security that unifies vulnerability detection, infrastructure-as-code misconfiguration scanning, secret detection, and software license scanning into a single command-line tool. It was originally created by developer Teppei Fukuda as a personal project and was brought under the Aqua Security open-source umbrella in 2019, after which Fukuda joined the company to continue leading its development.$q$, $q$The tool is designed to scan across the full software supply chain: container images, application filesystems, git repositories, virtual machine images, and live Kubernetes clusters. This breadth means teams can use one tool, rather than stitching together separate scanners for containers, code, and cloud configuration, to get consistent security findings across their stack.$q$, $q$Trivy is distributed under the Apache 2.0 license and ships as a dependency-free, single static binary, which has helped it become one of the most widely adopted open-source scanners in the cloud-native ecosystem, with tens of thousands of GitHub stars and hundreds of contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Trivy's core strength is breadth combined with simplicity: it detects vulnerabilities in both operating system packages (Alpine, Debian, RHEL, and others) and language-specific dependencies (npm, pip, Go modules, and more), pulling data from the Aqua Vulnerability Database and other public advisories, and it is noted for maintaining low false-positive rates even on notoriously noisy distributions.$q$, $q$Beyond vulnerabilities, Trivy scans Infrastructure-as-Code files for misconfigurations, scans source code and file systems for hardcoded secrets, checks open-source license compliance, and can generate a Software Bill of Materials (SBOM) for any scanned target. It also supports Kubernetes-native scanning, including generating a Kubernetes Bill of Materials (KBOM) that inventories cluster components and their vulnerabilities.$q$, $q$Because it requires no database setup or external middleware, Trivy integrates cleanly into CI/CD pipelines, pre-commit hooks, IDE extensions like the VS Code integration, and container registries, giving teams a fast feedback loop that fits naturally into existing DevSecOps workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Trivy scanner is entirely free and open source under the Apache 2.0 license, with no feature limitations, usage caps, or paywalls between the community and any commercial tier; every scanning capability described above is available at no cost.$q$, $q$Aqua Security monetizes separately through the Aqua Platform, a commercial cloud-native application protection platform (CNAPP) built on top of Trivy's scanning engine that adds centralized dashboards, runtime protection, policy enforcement, and enterprise support. Aqua Platform pricing is custom and requires contacting Aqua Security's sales team; it is a distinct commercial product rather than a paid tier of Trivy itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2d2c7247-cad0-4d55-bf16-9fd4c2b6499d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
