INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bc3cd59-7fc3-4389-bfc4-17fcf18c8ed8', $q$75+ native integrations$q$, $q$Connects with finance and procurement systems including Oracle, Workday, QuickBooks, and Salesforce.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bc3cd59-7fc3-4389-bfc4-17fcf18c8ed8', $q$Buyer-only positioning$q$, $q$Operates with no supplier relationships or marketplace commissions, avoiding conflicts of interest.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bc3cd59-7fc3-4389-bfc4-17fcf18c8ed8', $q$Deep pricing benchmark data drawn from over 100,000 analyzed software deals$q$, 0);
