INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Autoscaling$q$, $q$Dynamically scales applications to meet changing demand.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Fast rolling deployments$q$, $q$Enables continuous delivery with reliable, low-downtime deployment workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Extensible, pluggable architecture$q$, $q$Allows platform teams to build custom components on top of the core platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$CLI and web dashboard$q$, $q$Provides developer-facing tools for deploying and managing applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Multi-tenancy$q$, $q$Supports hosting many teams and applications on shared underlying infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Completely free and open source under the permissive BSD-3-Clause license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Proven at extreme production scale, including Globo's live television voting systems$q$, 1);
