INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Much of the project's community history and discussion content is in Portuguese$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$What is Tsuru?$q$, $q$Tsuru is a free, open-source Platform-as-a-Service that lets developers deploy applications on Docker and Kubernetes without managing infrastructure directly.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Who created Tsuru?$q$, $q$Tsuru was created in 2012 by developer Andrews Medina and colleagues at Globo.com, Brazil's largest media group.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Is Tsuru free?$q$, $q$Yes, Tsuru is completely free and open source under the 3-Clause BSD license, with no official paid tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$What license does Tsuru use?$q$, $q$Tsuru is released under the permissive 3-Clause BSD license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Does Tsuru require Kubernetes?$q$, $q$Yes, modern versions of Tsuru run natively on Kubernetes and Docker as their underlying infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$How is Tsuru different from Heroku?$q$, $q$Tsuru offers a similar git-push deployment experience to Heroku but is self-hosted and open source, giving organizations full control of the underlying infrastructure instead of relying on a managed vendor.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Who uses Tsuru in production?$q$, $q$Tsuru has been used in production by Globo, QDQ Media, Hotel Urbano, Jumia, and Stone, among others.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Can Tsuru run any programming language?$q$, $q$Yes, Tsuru supports any language or framework via buildpacks or direct Docker image deployment.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Internal developer platform on Kubernetes$q$, $q$Platform engineering teams building a Heroku-like self-service deployment experience on top of their own Kubernetes clusters.$q$, $q$Platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$High-traffic media and live-event scaling$q$, $q$Media and broadcast companies needing to scale application deployments rapidly for live-event traffic spikes.$q$, $q$Media, broadcast, and high-traffic consumer companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Cloud-native education$q$, $q$Computer science programs and bootcamps teaching students PaaS architecture and Kubernetes-based deployment using a real production codebase.$q$, $q$Educators and computer science students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full PaaS control plane and CLI","Docker and Kubernetes-native deployment","Multi-cluster application management","Autoscaling","BSD-3-Clause license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$overview$q$, $q$What Is Tsuru$q$, 2, ARRAY[$q$Tsuru is an open-source Platform-as-a-Service that lets development teams deploy applications without managing the underlying servers, container orchestration, or scaling infrastructure themselves. It originated in 2012 inside Globo.com, Brazil's largest media conglomerate, where developer Andrews Medina and colleagues built it to solve the company's own need to deploy and scale a large number of internal applications reliably, including systems that support massive real-time traffic spikes during live television events.$q$, $q$The project was released publicly as open source under the 3-Clause BSD license and has since evolved into a general-purpose cloud-native platform built on components from the Cloud Native Computing Foundation ecosystem, running on Docker and Kubernetes. It gives platform and infrastructure teams the ability to manage distributed applications across multiple Kubernetes clusters and regions from a single point of control.$q$, $q$Tsuru is positioned as an open-source alternative to commercial PaaS products like Heroku or Render, aimed at organizations that want the simplicity of a git-push-to-deploy workflow while retaining full ownership and control of the infrastructure it runs on, since there is no official managed cloud version, only the self-hosted open-source platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tsuru supports deploying applications written in any programming language or framework, either through buildpacks similar to Heroku's or by deploying prebuilt Docker images directly, giving teams flexibility in how they package their applications for the platform.$q$, $q$The platform is designed for scale and resilience: it supports managing applications across multiple Kubernetes clusters and geographic regions from a single control plane, includes autoscaling to dynamically grow application capacity in response to demand, and is built to support fast, reliable rolling deployments that enable continuous delivery workflows.$q$, $q$Because Tsuru is designed to be extensible and pluggable, platform teams can build custom components on top of its core rather than being limited to a fixed feature set, which has allowed organizations like Globo to adapt it to highly specific operational needs, such as handling voting traffic for live television broadcasts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tsuru is entirely free and open source under the 3-Clause BSD license. There is no official managed cloud product or subscription fee; organizations download and run the Tsuru control plane on their own Kubernetes infrastructure.$q$, $q$Because there is no vendor-hosted tier, the real cost of adopting Tsuru is the underlying Kubernetes infrastructure an organization provisions and operates, plus the engineering time required to deploy, configure, and maintain the platform itself, rather than any licensing fee paid to a Tsuru vendor.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a8012fa-de58-422c-8781-450f465f4beb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
