-- Enrichment marathon batch: TRIP, Trivy, Tropic, TruffleHog, Trunk.io, TrustArc, Tryton, Tsuru

-- в”Ђв”Ђ TRIP в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$TRIP is a free, open-source, self-hosted map tracker and trip planner that lets users pin points of interest and organize multi-day itineraries without ads or tracking.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TRIP Review: Self-Hosted Trip Planner and POI Map Tracker$q$, seo_title),
  seo_meta_description = COALESCE($q$TRIP is a free, open-source self-hosted app for mapping points of interest and planning multi-day trips. See features, setup, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TRIP is a free, open-source, self-hostable web application created and maintained by a developer known as itskovacs, distributed on GitHub under the MIT license. It is a minimalist points-of-interest (POI) map tracker and trip planner: users pin locations they want to visit or have visited on an interactive map, organize those pins into categorized collections, and build multi-day trip itineraries with day-by-day plans that can be shared with travel companions for collaborative planning. The project explicitly markets itself as having no telemetry, no tracking, and no advertisements, appealing to privacy-conscious self-hosters who prefer to own their travel data rather than store it in a commercial app. TRIP is deployed as a Docker container (a single command such as docker run with a mounted storage volume) or via Docker Compose, making it a natural fit for home-lab and self-hosting communities that already run tools like Cloudron or Unraid. A public demo is hosted at itskovacs-trip.netlify.app so prospective users can try the interface before self-hosting. The project has seen sustained development with dozens of releases and hundreds of commits, and has accumulated roughly 1.7k GitHub stars, indicating meaningful traction within the self-hosted-software niche. Because it is a solo-maintainer open-source project rather than a company, there is no traditional pricing page, sales team, or enterprise tier: the entire feature set is free, and the only monetization is optional sponsorship via Ko-fi. TRIP differs from mainstream travel planners like Google My Maps, Wanderlog, or TripIt in that it requires self-hosting and offers no cloud-hosted paid plan, trading convenience for full data ownership, no vendor lock-in, and no recurring subscription cost. It is best suited to technically comfortable travelers who already self-host other services and want a lightweight, ad-free way to track places and plan trips.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd1da66a-312f-432a-8e37-1dc816cc5520';

