-- в”Ђв”Ђ Trunk.io в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Trunk.io is a developer tooling platform that combines a universal code-quality metalinter with a flaky-test-aware CI merge queue to help engineering teams keep their codebase and pipelines clean.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Trunk.io Review: Code Quality Linter and CI Merge Queue$q$, seo_title),
  seo_meta_description = COALESCE($q$Trunk.io unifies 100+ linters and formatters with a flaky-test-aware merge queue to keep CI green. See pricing, features, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Trunk.io is a developer tooling company founded in 2021 and headquartered in San Francisco, California. It raised a 25 million dollar Series A round in April 2022 co-led by Andreessen Horowitz and Initialized Capital to build what it describes as a developer experience platform for large-scale software teams. The company's two flagship products are Trunk Check, a metalinter that wraps more than 100 existing code-checking tools such as ESLint, Prettier, and Ruff behind a single configuration and CLI so teams do not need to install and maintain dozens of separate linters, and Trunk Merge, a merge queue that automatically detects, quarantines, and eliminates flaky tests while running a flake-aware parallel merge queue to keep the main branch green and reduce wasted CI spend. Trunk is used by engineering teams at companies including Brex, Faire, Zillow, BetterUp, and Caseware. Pricing follows a freemium model: the Free plan supports up to five active repository committers and up to five million test spans per month at no cost, and is usable indefinitely by small teams and public repositories. The Team plan removes the committer cap and adds the merge queue, Slack notifications, and admin controls, billed on a custom per-committer basis that is not published and requires contacting sales. An Enterprise plan adds SAML single sign-on, on-premise deployment, and dedicated support, also via custom contract. All tiers include SOC 2 Type 2 compliance and US data residency. Trunk.io differs from point-solution linters or standalone merge-queue tools like Mergify by bundling both code-quality enforcement and CI reliability tooling into one platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '777bc7e4-e559-41dd-89c8-76328f01c9ca';

