-- в”Ђв”Ђ Tsuru в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tsuru is a free, open-source, extensible Platform-as-a-Service originally built at Globo.com that uses Docker and Kubernetes to let developers deploy applications in any language without managing infrastructure.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Rio de Janeiro, Brazil$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Tsuru Review: Open-Source Platform-as-a-Service (PaaS)$q$, seo_title),
  seo_meta_description = COALESCE($q$Tsuru is a free, open-source PaaS built by Globo.com that runs on Docker and Kubernetes. See features, self-hosting details, and Heroku alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tsuru is a free, open-source Platform-as-a-Service that was born in 2012 inside Globo.com, Brazil's largest media and broadcasting group, where it was created by developer Andrews Medina and a team facing the challenge of deploying and scaling large numbers of applications reliably, including systems supporting live television events such as Big Brother Brasil audience voting, which has needed to handle millions of votes per minute. Tsuru was released as open source under the permissive 3-Clause BSD license and is built on components from the Cloud Native Computing Foundation stack, running natively on Docker and Kubernetes. It lets developers deploy applications written in any language or framework, either through buildpacks or direct Docker images, and gives platform teams a single control point to manage applications across multiple Kubernetes clusters and regions, with autoscaling to handle variable demand. Because it is open source and self-hosted rather than a managed SaaS, there is no vendor lock-in or subscription fee; organizations run their own Tsuru control plane on their own Kubernetes infrastructure. Beyond Globo itself, the project has historically been used in production by companies including QDQ Media, Hotel Urbano, Jumia, and Stone, and it continues to see active development, with releases such as version 1.27.0 shipping in July 2025. Tsuru is frequently described as an open-source alternative to Heroku or Render for teams that want Heroku-style developer ergonomics (a simple git-push deployment workflow) while retaining full control of the underlying infrastructure. It has also found a niche in software engineering education, where researchers have documented using Tsuru to teach students PaaS and cloud-native deployment concepts in a real, production-grade codebase.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5a8012fa-de58-422c-8781-450f465f4beb';

